import{_ as r,o as a,c,a0 as t}from"./chunks/framework.CEvT70OL.js";const p="/typescratcherDoc/web/typescratcher_header.png",m=JSON.parse('{"title":"TypeScracherとは何？","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"01_introduction/index.md","filePath":"01_introduction/index.md"}'),i={name:"01_introduction/index.md"};function h(o,e,d,n,s,_){return a(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="typescracherとは何" tabindex="-1">TypeScracherとは何？ <a class="header-anchor" href="#typescracherとは何" aria-label="Permalink to &quot;TypeScracherとは何？&quot;">​</a></h1><p>『<code>TypeScratcher</code>』は、コードプログラミングにより、Scratch3風の動きを実現する『<code>Typescript</code>』で書かれたゲームエンジンのライブラリです。</p><p>Scratch3のコアライブラリである『Scratch-Render』/『Scratch-Audio』を組み込んでおり、コードプログラミングでありながらも、Scratch3と同等の動きを提供可能です。<br><br></p><p><img src="'+p+'" alt="画像"></p><h2 id="作者-amami-harhid-より" tabindex="-1">作者(Amami-Harhid)より <a class="header-anchor" href="#作者-amami-harhid-より" aria-label="Permalink to &quot;作者(Amami-Harhid)より&quot;">​</a></h2><p>Typescriptでプログラミングができるゲームエンジン『TypeScratcher』を作りました。</p><p>Scratch3に慣れ親しんだ方々のもつ、Scratch3のノウハウや感覚を、コードプログラミングでも生かしてもらいたいなぁ、そんなゲームエンジンがあったらいいなぁ！と思い立ち、作った次第です。</p><p>マニュアルをみなくても何となくコードをかけるように、TypeScratcherが必要なコードを教えてくれるよう、コード補完の恩恵をフル活用するため、Typescriptを使って実装しています。</p><p>なんとなくコードがかけてしまうと思うので、Scratch3からコードプログラミングへの移行を助けてくれるだろうと思います。</p><p>こんな動きは『Scratch3』ではどうやって書いていたっけ？を入口にして、コードプログラミングの世界へ進んでみてください。 Scratch3を愛する方々なら楽しんでいただけると思う学習用ゲームエンジンだと思います。</p><p>利用条件は「ゆるーい」ものですので、子どもさんの教育にかかわる方々（学校・教室）も安心してご利用ください。後から「やっぱり金寄こせ」とは言いません、基本的に「無償」でご利用いただけます。</p><hr><p>『TypeScratcher』を楽しんでみてくださいね。</p><p>ＳＮＳ拡散希望よろしくです。</p><p>それと作者のことも応援してもらうととてもうれしいです(😄)</p>',15)])])}const l=r(i,[["render",h]]);export{m as __pageData,l as default};
